public static boolean equals(CharSequence cs1, CharSequence cs2) {
    if (cs1 instanceof Name && cs2 instanceof Name) { // If both are names
        return ((Name) cs1).contentEquals((Name) cs2);
    } else if (cs1 instanceof String && cs2 instanceof String) { // If both are strings
        return ((String) cs1).contentEquals((String) cs2);
    } else if (cs1 != null && cs2 != null) { // Neither are special cases
        int length = cs1.length();
        if (length == cs2.length()) {
            for (int i = 0; i < length; i++) {
                if (!(cs1.charAt(i) == cs2.charAt(i))) {
                    return false;
                }
            }
            return true;
        }
    }
    return cs1 == cs2;
}

